import{_ as e,o as i,c as a,a2 as t}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"Model Providers","description":"","frontmatter":{},"headers":[],"relativePath":"manual/model-providers.md","filePath":"manual/model-providers.md","lastUpdated":null}'),n={name:"manual/model-providers.md"};function r(o,s,l,h,d,p){return i(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="model-providers" tabindex="-1">Model Providers <a class="header-anchor" href="#model-providers" aria-label="Permalink to &quot;Model Providers&quot;">​</a></h1><p>Autofac selects its model provider through the <code>Anthropic</code> configuration section. The section name remains <code>Anthropic</code> for compatibility, but it can select Anthropic, OpenAI-compatible endpoints, LiteLLM, Azure OpenAI through LiteLLM or OpenAI-compatible routing, the mock provider, or automatic behavior.</p><h2 id="provider-choices" tabindex="-1">Provider choices <a class="header-anchor" href="#provider-choices" aria-label="Permalink to &quot;Provider choices&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Provider</th><th>Use when</th></tr></thead><tbody><tr><td><code>mock</code></td><td>You need deterministic, tokenless demos, local development, or CI.</td></tr><tr><td><code>anthropic</code></td><td>You are using Anthropic directly.</td></tr><tr><td><code>openai</code></td><td>You are using an OpenAI Chat Completions-compatible endpoint.</td></tr><tr><td><code>litellm</code></td><td>You route model traffic through LiteLLM or another compatible proxy.</td></tr><tr><td><code>auto</code></td><td>You want Autofac to infer behavior from configured credentials.</td></tr></tbody></table><p>When no usable provider is configured, Autofac uses a safe null client and agent steps report that no model is configured.</p><h2 id="configure-a-mock-provider" tabindex="-1">Configure a mock provider <a class="header-anchor" href="#configure-a-mock-provider" aria-label="Permalink to &quot;Configure a mock provider&quot;">​</a></h2><p>Use this for local demos and tests:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__Provider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">mock</span></span></code></pre></div><p>Mock runs should produce deterministic output and zero model cost.</p><h2 id="configure-a-real-provider" tabindex="-1">Configure a real provider <a class="header-anchor" href="#configure-a-real-provider" aria-label="Permalink to &quot;Configure a real provider&quot;">​</a></h2><p>Set the provider, API key, model, and limits through environment variables, secret stores, appsettings, Helm values, or the Admin Settings page.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__Provider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">anthropic</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__ApiKey</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">secret</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__Model</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">claude-sonnet-4-6</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__MaxTokens</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">4096</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__MaxToolIterations</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">10</span></span></code></pre></div><p>For an OpenAI-compatible or LiteLLM endpoint:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__Provider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">litellm</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__ApiBaseUrl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://litellm:4000/v1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__ApiKey</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">secret</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__Model</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">model-name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="configure-run-budgets" tabindex="-1">Configure run budgets <a class="header-anchor" href="#configure-run-budgets" aria-label="Permalink to &quot;Configure run budgets&quot;">​</a></h2><p>Use budgets to prevent runaway agent loops:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__MaxRunCostUsd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">2.00</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Anthropic__MaxRunTokens</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">100000</span></span></code></pre></div><p>Set either value to <code>0</code> for unlimited. When a run reaches its budget, Autofac stops further model calls with a <code>budget_exceeded</code> status.</p><h2 id="rotate-model-secrets" tabindex="-1">Rotate model secrets <a class="header-anchor" href="#rotate-model-secrets" aria-label="Permalink to &quot;Rotate model secrets&quot;">​</a></h2><p>Administrators can rotate supported model secrets from Settings. Secret inputs are write-only, the browser clears the value after save, and the API returns only configured/missing status, source, and fingerprint.</p><p>For production, prefer deployment-managed secrets over local file-backed settings writes:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Settings__AllowLocalSecretWrites</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">false</span></span></code></pre></div><h2 id="readiness-checks" tabindex="-1">Readiness checks <a class="header-anchor" href="#readiness-checks" aria-label="Permalink to &quot;Readiness checks&quot;">​</a></h2><p>Use the Settings readiness check for model providers before running production workflows. The check validates local configuration completeness and writes a redacted audit record. It should not mutate external systems.</p>`,24)])])}const u=e(n,[["render",r]]);export{k as __pageData,u as default};
